/**
 * Page Renderer - Renders page sections for public view
 * Author: generated by Amazon Q
 * Created: 2024-01-15
 */

import React from 'react';
import { SectionRenderer } from '@/lib/page-builder/section-renderer';
import { SectionConfig } from '@/lib/page-builder/section-schemas';

interface PageRendererProps {
  sections: SectionConfig[];
  isPreview?: boolean;
}

export function PageRenderer({ sections, isPreview = false }: PageRendererProps) {
  // Ensure sections is an array
  const sectionsArray = Array.isArray(sections) ? sections : [];
  
  if (sectionsArray.length === 0) {
    return (
      <div className="min-h-screen bg-slate-50 dark:bg-slate-900 flex items-center justify-center">
        <div className="text-center">
          <h1 className="text-2xl font-bold text-slate-900 dark:text-white mb-4">
            No content available
          </h1>
          <p className="text-slate-600 dark:text-slate-300">
            This page has no sections to display.
          </p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen">
      {sectionsArray.map((section) => (
        <SectionRenderer
          key={section.id}
          section={section}
          isBuilder={false}
        />
      ))}
    </div>
  );
}